import json
import re
from datetime import datetime

# Read the review data from the file using locals()
review_file = locals()['var_functions.query_db:8']
with open(review_file, 'r') as f:
    reviews = json.load(f)

# Function to parse various date formats
def parse_date(date_str):
    if not date_str:
        return None

    # Try different date formats
    formats = [
        '%B %d, %Y at %I:%M %p',  # August 01, 2016 at 03:44 AM
        '%d %B %Y, %H:%M',        # 29 May 2013, 23:01
        '%Y-%m-%d %H:%M:%S',      # 2016-08-15 21:16:00
        '%Y-%m-%d %H:%M:%S.%f',   # With microseconds
        '%Y-%m-%d %H:%M:%S',      # 2013-07-08 21:47:00
    ]

    for fmt in formats:
        try:
            return datetime.strptime(date_str, fmt)
        except:
            continue

    # Try to extract date using regex patterns
    # Pattern for "21 May 2016, 18:48"
    match = re.search(r'(\d{1,2})\s+([A-Za-z]+)\s+(\d{4})', date_str)
    if match:
        day, month, year = match.groups()
        try:
            return datetime.strptime(f"{day} {month} {year}", '%d %B %Y')
        except:
            pass

    return None

# Filter reviews for date range
start_date = datetime(2016, 1, 1)
end_date = datetime(2016, 6, 30, 23, 59, 59)

filtered_reviews = []
for review in reviews:
    date_str = review.get('date', '')
    parsed_date = parse_date(date_str)

    if parsed_date and start_date <= parsed_date <= end_date:
        filtered_reviews.append(review)

# Group by business and calculate average rating with review count
from collections import defaultdict

business_stats = defaultdict(lambda: {'ratings': [], 'review_count': 0})

for review in filtered_reviews:
    business_ref = review.get('business_ref')
    rating = int(review.get('rating', 0))

    if business_ref:
        business_stats[business_ref]['ratings'].append(rating)
        business_stats[business_ref]['review_count'] += 1

# Calculate averages and filter businesses with at least 5 reviews
business_averages = []
for business_ref, stats in business_stats.items():
    if stats['review_count'] >= 5:
        avg_rating = sum(stats['ratings']) / len(stats['ratings'])
        business_averages.append({
            'business_ref': business_ref,
            'avg_rating': avg_rating,
            'review_count': stats['review_count']
        })

# Sort by average rating descending
business_averages.sort(key=lambda x: x['avg_rating'], reverse=True)

print('__RESULT__:')
print(json.dumps({
    'total_reviews_in_range': len(filtered_reviews),
    'businesses_with_5plus_reviews': len(business_averages),
    'top_businesses': business_averages[:5]
}))

